import React, { createContext, useContext, useState, useEffect } from 'react';
import api from '../services/api';

export interface User {
    id: string;
    name: string;
    email: string;
    avatar?: string;
}

interface AuthContextData {
    user: User | null;
    loadUser: () => void;
    logout: () => void;
}

const AuthContext = createContext<AuthContextData>({} as AuthContextData);

export const AuthProvider: React.FC<{ children: React.ReactNode }> = ({ children }) => {
    const [user, setUser] = useState<User | null>(() => {
        const storedUser = localStorage.getItem('@Famask:user');
        return storedUser ? JSON.parse(storedUser) : null;
    });



    const loadUser = () => {
        const storedUser = localStorage.getItem('@Famask:user');
        if (storedUser) {
            setUser(JSON.parse(storedUser));
        }
    };

    const logout = async () => {
        try {
            await api.post('/api/auth/logout');
        } catch (e) {
            console.error(e);
        }
        localStorage.removeItem('@Famask:token');
        localStorage.removeItem('@Famask:user');
        setUser(null);
    };

    useEffect(() => {
        loadUser();
    }, []);

    return (
        <AuthContext.Provider value={{ user, loadUser, logout }}>
            {children}
        </AuthContext.Provider>
    );
};

export const useAuth = () => useContext(AuthContext);

import React, { useEffect, useState } from 'react';
import { useNavigate } from 'react-router-dom';
import api from '../services/api';
import { useAuth } from '../context/AuthContext';
import { Plus, Users, LayoutDashboard, Home, ArrowRight, LogOut, Download } from 'lucide-react';
import toast from 'react-hot-toast';

interface Group {
    id: string;
    name: string;
    members: Array<{ user: { id: string; name: string } }>;
}

const AVATAR_MAP: Record<string, string> = {
    fox: '🦊', cat: '🐱', dog: '🐶', panda: '🐼', koala: '🐨',
    lion: '🦁', tiger: '🐯', monkey: '🐵', unicorn: '🦄', alien: '👽'
};

const Dashboard: React.FC = () => {
    const { user, logout } = useAuth();
    const [groups, setGroups] = useState<Group[]>([]);
    const [loading, setLoading] = useState(true);
    const [newGroupName, setNewGroupName] = useState('');
    const [creating, setCreating] = useState(false);

    const [joinCode, setJoinCode] = useState('');
    const [joining, setJoining] = useState(false);

    // PWA Install Logic
    const [deferredPrompt, setDeferredPrompt] = useState<any>(null);
    const [showInstallBtn, setShowInstallBtn] = useState(false);

    useEffect(() => {
        const handler = (e: any) => {
            e.preventDefault();
            setDeferredPrompt(e);
            setShowInstallBtn(true);
        };
        window.addEventListener('beforeinstallprompt', handler);
        return () => window.removeEventListener('beforeinstallprompt', handler);
    }, []);

    const handleInstallClick = async () => {
        if (!deferredPrompt) return;
        deferredPrompt.prompt();
        const { outcome } = await deferredPrompt.userChoice;
        if (outcome === 'accepted') {
            setShowInstallBtn(false);
        }
        setDeferredPrompt(null);
    };

    const navigate = useNavigate();

    const fetchGroups = async () => {
        try {
            const { data } = await api.get('/api/groups');
            setGroups(data);
        } catch (err) {
            console.error(err);
        } finally {
            setLoading(false);
        }
    };

    useEffect(() => {
        fetchGroups();
    }, []);

    const handleCreateGroup = async (e: React.FormEvent) => {
        e.preventDefault();
        if (!newGroupName.trim()) return;

        setCreating(true);
        try {
            const { data } = await api.post('/api/groups', { name: newGroupName });
            toast.success('Grupo criado com sucesso!');
            navigate(`/group/${data.id}`);
        } catch (err: any) {
            console.error(err);
            const message = err.response?.data?.error || 'Erro ao criar grupo.';
            toast.error(message);
        } finally {
            setCreating(false);
        }
    };

    const handleJoinGroup = async (e: React.FormEvent) => {
        e.preventDefault();
        if (!joinCode.trim()) return;

        setJoining(true);
        try {
            const { data } = await api.post('/api/groups/join', { inviteCode: joinCode.trim().toUpperCase() });
            navigate(`/group/${data.groupId}`);
            toast.success('Entrou na Família com sucesso!');
        } catch (err: any) {
            toast.error(err.response?.data?.error || 'Erro ao entrar. Verifique o código.');
        } finally {
            setJoining(false);
        }
    };

    return (
        <div style={{ padding: '40px 20px', maxWidth: '1000px', margin: '0 auto', width: '100%' }}>

            {/* Professional Header / Hero */}
            <header style={{
                display: 'flex',
                justifyContent: 'space-between',
                alignItems: 'center',
                marginBottom: '48px',
                paddingBottom: '24px',
                borderBottom: '1px solid var(--border-color)'
            }}>
                <div style={{ display: 'flex', alignItems: 'center', gap: '16px' }}>
                    <div style={{ padding: '12px', background: 'rgba(99, 102, 241, 0.1)', borderRadius: '12px', color: 'var(--primary)' }}>
                        <LayoutDashboard size={32} />
                    </div>
                    <div>
                        <div style={{ display: 'flex', alignItems: 'center', gap: '12px' }}>
                            <h1 className="title" style={{ margin: 0, fontSize: '2rem' }}>Meus Grupos Familiares</h1>
                            {showInstallBtn && (
                                <button
                                    onClick={handleInstallClick}
                                    className="animate-in"
                                    style={{
                                        background: 'var(--success)',
                                        color: 'white',
                                        border: 'none',
                                        padding: '4px 12px',
                                        borderRadius: '20px',
                                        fontSize: '0.75rem',
                                        fontWeight: 'bold',
                                        display: 'flex',
                                        alignItems: 'center',
                                        gap: '6px',
                                        cursor: 'pointer',
                                        boxShadow: '0 4px 12px rgba(34, 197, 94, 0.3)'
                                    }}
                                >
                                    <Download size={14} /> Instalar App
                                </button>
                            )}
                        </div>
                        <div style={{ display: 'flex', alignItems: 'center', gap: '8px', marginTop: '4px' }}>
                            <span style={{ fontSize: '1.4rem' }}>{user?.avatar ? AVATAR_MAP[user.avatar] : '👤'}</span>
                            <p style={{ color: 'var(--text-secondary)', margin: 0, fontSize: '1.1rem' }}>
                                Olá, {user?.name || 'Visitante'}
                            </p>
                        </div>
                    </div>
                </div>
                <button className="btn btn-secondary" onClick={logout}>
                    <LogOut size={16} /> Sair
                </button>
            </header>

            <div style={{ display: 'grid', gridTemplateColumns: 'repeat(auto-fit, minmax(300px, 1fr))', gap: '24px', marginBottom: '48px' }}>
                {/* Create new Group Card */}
                <div className="glass glass-card animate-in" style={{ display: 'flex', flexDirection: 'column', justifyContent: 'center' }}>
                    <h3 style={{ marginBottom: '16px', color: 'var(--text-primary)' }}>Criar Novo Grupo</h3>
                    <form onSubmit={handleCreateGroup} style={{ display: 'flex', flexDirection: 'column', gap: '12px' }}>
                        <input
                            type="text"
                            className="form-input"
                            placeholder="Nome da Família"
                            value={newGroupName}
                            onChange={e => setNewGroupName(e.target.value)}
                            required
                        />
                        <button type="submit" className="btn btn-primary" disabled={creating} style={{ width: '100%' }}>
                            <Plus size={18} /> Criar
                        </button>
                    </form>
                </div>

                {/* Join Group Card */}
                <div className="glass glass-card animate-in" style={{ display: 'flex', flexDirection: 'column', justifyContent: 'center', animationDelay: '0.05s' }}>
                    <h3 style={{ marginBottom: '16px', color: 'var(--text-primary)' }}>Tem um código de Convite?</h3>
                    <form onSubmit={handleJoinGroup} style={{ display: 'flex', flexDirection: 'column', gap: '12px' }}>
                        <input
                            type="text"
                            className="form-input"
                            placeholder="Ex: ABC123"
                            value={joinCode}
                            onChange={e => setJoinCode(e.target.value.toUpperCase())}
                            maxLength={6}
                            required
                        />
                        <button type="submit" className="btn btn-secondary" disabled={joining} style={{ width: '100%', borderColor: 'var(--primary)', color: 'var(--primary)' }}>
                            <Users size={18} /> Entrar na Família
                        </button>
                    </form>
                </div>
            </div>

            {loading ? (
                <div style={{ textAlign: 'center', padding: '40px', color: 'var(--text-secondary)' }}>Carregando seus grupos...</div>
            ) : groups.length === 0 ? (
                <div className="animate-in" style={{
                    textAlign: 'center',
                    padding: '64px 24px',
                    background: 'var(--glass-bg)',
                    borderRadius: 'var(--radius-lg)',
                    border: '1px dashed var(--border-color)'
                }}>
                    <Home size={48} color="var(--text-secondary)" style={{ opacity: 0.5, marginBottom: '16px' }} />
                    <h3 style={{ fontSize: '1.4rem', marginBottom: '8px' }}>Nenhuma família encontrada</h3>
                    <p style={{ color: 'var(--text-secondary)', maxWidth: '400px', margin: '0 auto' }}>
                        Crie um novo grupo acima ou peça o ID de convite para um membro de uma família já existente.
                    </p>
                </div>
            ) : (
                <div style={{ display: 'grid', gridTemplateColumns: 'repeat(auto-fill, minmax(280px, 1fr))', gap: '20px' }}>
                    {groups.map((group, index) => (
                        <div
                            key={group.id}
                            className="glass glass-card animate-in"
                            style={{
                                cursor: 'pointer',
                                animationDelay: `${index * 0.1}s`,
                                display: 'flex',
                                flexDirection: 'column',
                                justifyContent: 'space-between'
                            }}
                            onClick={() => navigate(`/group/${group.id}`)}
                        >
                            <div>
                                <h3 style={{ fontSize: '1.25rem', marginBottom: '8px' }}>{group.name}</h3>
                                <p style={{ color: 'var(--text-secondary)', fontSize: '0.9rem', display: 'flex', alignItems: 'center', gap: '6px' }}>
                                    <Users size={14} /> {group.members?.length || 0} Membros
                                </p>
                            </div>
                            <div style={{ marginTop: '24px', display: 'flex', justifyContent: 'flex-end' }}>
                                <div style={{ color: 'var(--primary)', display: 'flex', alignItems: 'center', gap: '4px', fontSize: '0.9rem', fontWeight: 500 }}>
                                    Acessar <ArrowRight size={16} />
                                </div>
                            </div>
                        </div>
                    ))}
                </div>
            )}
        </div>
    );
};

export default Dashboard;

import React, { useEffect, useState } from 'react';
import { useParams, useNavigate } from 'react-router-dom';
import api from '../services/api';
import { ArrowLeft, CheckCircle2, Circle, Trash2, Plus, UserPlus, Copy, Trophy, Calendar, CheckSquare } from 'lucide-react';
import toast from 'react-hot-toast';
import { useAuth } from '../context/AuthContext';

interface GroupData {
    id: string;
    inviteCode: string;
    name: string;
    members: Array<{ score: number; role: string; user: { id: string; name: string, avatar?: string } }>;
}

interface Reward {
    id: string;
    title: string;
    pointsCost: number;
}

interface Task {
    id: string;
    title: string;
    description: string | null;
    category: string | null;
    isCompleted: boolean;
    isDaily: boolean;
    points: number;
    creator: { name: string };
    completer: { name: string } | null;
    subtasks?: Array<{ id: string; title: string; isCompleted: boolean }>;
}

const AVATAR_MAP: Record<string, string> = {
    fox: '🦊', cat: '🐱', dog: '🐶', panda: '🐼', koala: '🐨',
    lion: '🦁', tiger: '🐯', monkey: '🐵', unicorn: '🦄', alien: '👽'
};

const GroupDetails: React.FC = () => {
    const { id } = useParams<{ id: string }>();
    const navigate = useNavigate();
    const { user } = useAuth();

    const [tasks, setTasks] = useState<Task[]>([]);
    const [rewards, setRewards] = useState<Reward[]>([]);
    const [groupData, setGroupData] = useState<GroupData | null>(null);
    const [loading, setLoading] = useState(true);

    // New Task States
    const [newTaskTitle, setNewTaskTitle] = useState('');
    const [newTaskCategory, setNewTaskCategory] = useState('geral');
    const [newTaskPoints, setNewTaskPoints] = useState<number>(10);
    const [newTaskIsDaily, setNewTaskIsDaily] = useState<boolean>(false);

    // Add member
    const [newMemberEmail, setNewMemberEmail] = useState('');

    // Reward Creation States
    const [showRewardForm, setShowRewardForm] = useState(false);
    const [newRewardTitle, setNewRewardTitle] = useState('');
    const [newRewardPoints, setNewRewardPoints] = useState(50);

    // Subtask Inline States
    const [addingSubtaskTo, setAddingSubtaskTo] = useState<string | null>(null);
    const [newSubtaskTitle, setNewSubtaskTitle] = useState('');

    // Custom Confirmation Modal
    const [confirmModal, setConfirmModal] = useState<{
        isOpen: boolean;
        title: string;
        message: string;
        onConfirm: () => void;
    }>({
        isOpen: false,
        title: '',
        message: '',
        onConfirm: () => { }
    });

    const openConfirm = (title: string, message: string, onConfirm: () => void) => {
        setConfirmModal({ isOpen: true, title, message, onConfirm });
    };

    const closeConfirm = () => {
        setConfirmModal({ ...confirmModal, isOpen: false });
    };

    const fetchTasks = async () => {
        try {
            const [tasksRes, groupRes, rewardsRes] = await Promise.all([
                api.get(`/api/tasks/${id}`),
                api.get(`/api/groups/${id}`),
                api.get(`/api/rewards/${id}`)
            ]);
            setTasks(tasksRes.data);
            setGroupData(groupRes.data);
            setRewards(rewardsRes.data);
        } catch (err: any) {
            console.error(err);
            const status = err.response?.status;
            const errorMsg = err.response?.data?.error || 'Erro ao carregar dados.';

            toast.error(`Falha: ${errorMsg} (${status})`);

            if (status === 401 || status === 403) {
                navigate('/');
            }
        } finally {
            setLoading(false);
        }
    };

    useEffect(() => {
        if (id) fetchTasks();
    }, [id]);

    const handleCreateTask = async (e: React.FormEvent) => {
        e.preventDefault();
        if (!newTaskTitle.trim()) return;
        try {
            await api.post('/api/tasks', {
                groupId: id,
                title: newTaskTitle,
                category: newTaskCategory,
                points: newTaskPoints,
                isDaily: newTaskIsDaily
            });
            setNewTaskTitle('');
            setNewTaskCategory('geral');
            setNewTaskPoints(10);
            setNewTaskIsDaily(false);
            fetchTasks();
        } catch (err) {
            console.error(err);
        }
    };

    const handleToggleTask = async (taskId: string, currentStatus: boolean) => {
        try {
            // Optimistic update
            setTasks(tasks.map(t => t.id === taskId ? { ...t, isCompleted: !currentStatus } : t));
            await api.patch(`/api/tasks/${taskId}`, { isCompleted: !currentStatus });
            fetchTasks(); // Refresh to get completer name
        } catch (err) {
            console.error(err);
            fetchTasks(); // Revert on err
        }
    };

    const handleToggleSubtask = async (taskId: string, subtaskId: string, currentStatus: boolean) => {
        try {
            // Optimistic update for subtask
            setTasks(tasks.map(t => {
                if (t.id === taskId && t.subtasks) {
                    return {
                        ...t,
                        subtasks: t.subtasks.map(st => st.id === subtaskId ? { ...st, isCompleted: !currentStatus } : st)
                    };
                }
                return t;
            }));
            await api.patch(`/api/tasks/${taskId}/subtasks/${subtaskId}`, { isCompleted: !currentStatus });
        } catch (err) {
            console.error(err);
            fetchTasks();
        }
    };

    const handleAddSubtask = async (taskId: string) => {
        if (!newSubtaskTitle.trim()) return;
        try {
            await api.post(`/api/tasks/${taskId}/subtasks`, { title: newSubtaskTitle });
            setNewSubtaskTitle('');
            setAddingSubtaskTo(null);
            fetchTasks();
        } catch (err) {
            console.error(err);
        }
    };

    const handleDeleteTask = (taskId: string) => {
        openConfirm(
            'Excluir Tarefa',
            'Tem certeza que deseja deletar permanentemente esta tarefa?',
            async () => {
                try {
                    await api.delete(`/api/tasks/${taskId}`);
                    setTasks(tasks.filter(t => t.id !== taskId));
                    toast.success('Tarefa removida.');
                    closeConfirm();
                } catch (err) {
                    console.error(err);
                    toast.error('Erro ao excluir (apenas admins ou donos podem).');
                    closeConfirm();
                }
            }
        );
    };

    const handleAddMember = async (e: React.FormEvent) => {
        e.preventDefault();
        if (!newMemberEmail.trim()) return;
        try {
            await api.post(`/api/groups/${id}/members`, { email: newMemberEmail });
            setNewMemberEmail('');
            toast.success('Membro adicionado!');
        } catch (err: any) {
            toast.error(err.response?.data?.error || 'Erro ao adicionar membro.');
        }
    };

    const handleCreateReward = async (e: React.FormEvent) => {
        e.preventDefault();
        if (!newRewardTitle.trim()) return;

        try {
            await api.post(`/api/rewards/${id}`, { title: newRewardTitle, pointsCost: Number(newRewardPoints) });
            toast.success('Recompensa criada!');
            setNewRewardTitle('');
            setNewRewardPoints(50);
            setShowRewardForm(false);
            fetchTasks();
        } catch (err: any) {
            toast.error(err.response?.data?.error || 'Erro ao criar.');
        }
    };

    const handleClaimReward = (rewardId: string, cost: number) => {
        openConfirm(
            'Resgatar Recompensa',
            `Deseja resgatar essa recompensa por ${cost} pts?`,
            async () => {
                try {
                    await api.post(`/api/rewards/claim/${rewardId}`);
                    toast.success('Recompensa resgatada com sucesso!');
                    fetchTasks();
                    closeConfirm();
                } catch (err: any) {
                    toast.error(err.response?.data?.error || 'Erro no resgate.');
                    closeConfirm();
                }
            }
        );
    };

    const handleDeleteReward = (rewardId: string) => {
        openConfirm(
            'Excluir Recompensa',
            'Deseja excluir permanentemente esta recompensa da loja?',
            async () => {
                try {
                    await api.delete(`/api/rewards/${rewardId}`);
                    fetchTasks();
                    toast.success('Recompensa excluída.');
                    closeConfirm();
                } catch (err: any) {
                    toast.error(err.response?.data?.error || 'Erro ao deletar recompensa.');
                    closeConfirm();
                }
            }
        );
    };

    const handleDeleteGroup = () => {
        openConfirm(
            'Deletar Família Inteira',
            'ATENÇÃO: Você está prestes a deletar completamente este grupo. Todas as tarefas, recompensas e pontuações serão apagadas permanentemente. Deseja continuar?',
            async () => {
                try {
                    await api.delete(`/api/groups/${id}`);
                    toast.success('Família deletada permanentemente.');
                    navigate('/');
                } catch (err: any) {
                    toast.error(err.response?.data?.error || 'Erro ao deletar família. (Apenas Admins)');
                    closeConfirm();
                }
            }
        );
    };

    return (
        <div style={{ padding: '40px 20px', maxWidth: '800px', margin: '0 auto', width: '100%' }}>
            <header style={{ display: 'flex', alignItems: 'center', justifyContent: 'space-between', gap: '16px', marginBottom: '40px', flexWrap: 'wrap' }}>
                <div style={{ display: 'flex', alignItems: 'center', gap: '16px' }}>
                    <button className="btn btn-secondary" onClick={() => navigate('/')} style={{ padding: '8px' }}>
                        <ArrowLeft size={20} />
                    </button>
                    <div>
                        <h1 className="title" style={{ fontSize: '1.8rem', margin: 0 }}>Tarefas da Família</h1>
                    </div>
                </div>

                <div style={{ display: 'flex', gap: '8px' }}>
                    <button
                        className="btn btn-secondary"
                        onClick={() => {
                            if (groupData?.inviteCode) {
                                navigator.clipboard.writeText(groupData.inviteCode);
                                toast.success('Código criado com 6 dígitos copiado!');
                            }
                        }}
                    >
                        <Copy size={16} /> Código de Convite
                    </button>
                    {groupData?.members.find(m => m.user.id === user?.id && m.role === 'Admin') && (
                        <button
                            className="btn"
                            style={{ background: 'rgba(239, 68, 68, 0.1)', color: 'var(--danger)', border: '1px solid rgba(239, 68, 68, 0.3)' }}
                            onClick={handleDeleteGroup}
                            title="Deletar Família"
                        >
                            <Trash2 size={16} /> Deletar
                        </button>
                    )}
                </div>
            </header>

            {/* Gamification Leaderboard */}
            {groupData && (
                <div className="glass glass-card animate-in" style={{ marginBottom: '32px', display: 'flex', gap: '24px', overflowX: 'auto', alignItems: 'center' }}>
                    <div style={{ display: 'flex', alignItems: 'center', gap: '8px', minWidth: 'max-content' }}>
                        <Trophy size={20} color="var(--primary)" />
                        <h3 style={{ margin: 0, fontSize: '1.2rem' }}>Ranking de Pontos</h3>
                    </div>
                    {groupData.members.map(member => (
                        <div key={member.user.id} style={{ display: 'flex', alignItems: 'center', gap: '8px', padding: '8px 16px', background: 'rgba(255,255,255,0.05)', borderRadius: 'var(--radius-sm)', whiteSpace: 'nowrap' }}>
                            <span style={{ fontSize: '1.2rem' }}>{AVATAR_MAP[member.user.avatar || 'fox']}</span>
                            <strong>{member.user.name}</strong>
                            <span style={{ color: 'var(--success)', fontWeight: 'bold' }}>{member.score} pts</span>
                        </div>
                    ))}
                </div>
            )}

            {/* Rewards Store */}
            <div className="glass glass-card animate-in" style={{ marginBottom: '32px' }}>
                <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '16px' }}>
                    <h3 style={{ margin: 0, fontSize: '1.2rem', display: 'flex', alignItems: 'center', gap: '8px' }}>
                        🎁 Loja de Recompensas
                    </h3>
                    <button className="btn btn-secondary" onClick={() => setShowRewardForm(!showRewardForm)} style={{ padding: '6px 12px', fontSize: '0.8rem' }}>
                        <Plus size={16} /> {showRewardForm ? 'Cancelar' : 'Nova (Admin)'}
                    </button>
                </div>

                {showRewardForm && (
                    <form onSubmit={handleCreateReward} className="animate-in" style={{ marginBottom: '24px', padding: '16px', borderRadius: 'var(--radius-md)', background: 'rgba(255,255,255,0.05)', display: 'flex', flexWrap: 'wrap', gap: '12px', alignItems: 'flex-end' }}>
                        <div style={{ flex: 1, minWidth: '200px' }}>
                            <label style={{ display: 'block', fontSize: '0.8rem', color: 'var(--text-secondary)', marginBottom: '4px' }}>Título da Recompensa</label>
                            <input
                                type="text"
                                className="form-input"
                                placeholder="Ex: 1h de Videogame"
                                value={newRewardTitle}
                                onChange={e => setNewRewardTitle(e.target.value)}
                                required
                            />
                        </div>
                        <div style={{ width: '120px' }}>
                            <label style={{ display: 'block', fontSize: '0.8rem', color: 'var(--text-secondary)', marginBottom: '4px' }}>Custo (pts)</label>
                            <input
                                type="number"
                                className="form-input"
                                value={newRewardPoints}
                                onChange={e => setNewRewardPoints(Number(e.target.value))}
                                min={1}
                                required
                            />
                        </div>
                        <button type="submit" className="btn btn-primary" style={{ height: '42px' }}>Criar</button>
                    </form>
                )}

                {rewards.length === 0 ? (
                    <p style={{ color: 'var(--text-secondary)', fontSize: '0.9rem', margin: 0 }}>Nenhuma recompensa cadastrada. Crie uma para engajar a família!</p>
                ) : (
                    <div style={{ display: 'flex', gap: '16px', overflowX: 'auto', paddingBottom: '8px' }}>
                        {rewards.map(reward => (
                            <div key={reward.id} style={{
                                minWidth: '160px',
                                padding: '16px',
                                background: 'rgba(255,255,255,0.03)',
                                border: '1px solid rgba(255,255,255,0.1)',
                                borderRadius: 'var(--radius-md)',
                                display: 'flex', flexDirection: 'column', gap: '12px'
                            }}>
                                <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'flex-start' }}>
                                    <strong style={{ fontSize: '1rem', lineHeight: 1.2 }}>{reward.title}</strong>
                                    <button onClick={() => handleDeleteReward(reward.id)} style={{ background: 'none', border: 'none', color: 'var(--text-secondary)', cursor: 'pointer', padding: 0 }} title="Excluir">
                                        <Trash2 size={14} />
                                    </button>
                                </div>
                                <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginTop: 'auto' }}>
                                    <span style={{ color: 'var(--primary)', fontWeight: 'bold', fontSize: '0.9rem' }}>{reward.pointsCost} pts</span>
                                    <button onClick={() => handleClaimReward(reward.id, reward.pointsCost)} className="btn btn-primary" style={{ padding: '4px 12px', fontSize: '0.8rem' }}>
                                        Resgatar
                                    </button>
                                </div>
                            </div>
                        ))}
                    </div>
                )}
            </div>

            {/* Add New Task */}
            <div className="glass glass-card animate-in" style={{ marginBottom: '32px' }}>
                <form onSubmit={handleCreateTask} style={{ display: 'flex', flexDirection: 'column', gap: '16px' }}>
                    <div style={{ display: 'flex', gap: '12px' }}>
                        <input
                            type="text"
                            className="form-input"
                            placeholder="O que precisa ser feito hoje?"
                            style={{ flex: 1, padding: '16px', fontSize: '1.1rem' }}
                            value={newTaskTitle}
                            onChange={e => setNewTaskTitle(e.target.value)}
                            required
                        />
                        <button type="submit" className="btn btn-primary" style={{ padding: '0 24px' }}>
                            <Plus size={20} />
                        </button>
                    </div>

                    <div style={{ display: 'flex', gap: '24px', flexWrap: 'wrap', alignItems: 'center' }}>
                        <select
                            className="form-input"
                            style={{ width: 'auto', padding: '8px 12px', fontSize: '0.9rem', cursor: 'pointer' }}
                            value={newTaskCategory}
                            onChange={e => setNewTaskCategory(e.target.value)}
                        >
                            <option value="geral">Geral</option>
                            <option value="limpeza">Casa & Limpeza</option>
                            <option value="mercado">Mercado</option>
                            <option value="escola">Escola/Estudos</option>
                            <option value="trabalho">Trabalho</option>
                        </select>
                        <label style={{ display: 'flex', alignItems: 'center', gap: '8px', color: 'var(--text-secondary)', cursor: 'pointer' }}>
                            <input
                                type="checkbox"
                                style={{ width: '18px', height: '18px', accentColor: 'var(--primary)' }}
                                checked={newTaskIsDaily}
                                onChange={e => setNewTaskIsDaily(e.target.checked)}
                            />
                            Tarefa Diária (Recorrente)
                        </label>
                        <label style={{ display: 'flex', alignItems: 'center', gap: '8px', color: 'var(--text-secondary)' }}>
                            Recompensa da Tarefa:
                            <input
                                type="number"
                                className="form-input"
                                style={{ width: '80px', padding: '4px 8px' }}
                                value={newTaskPoints}
                                onChange={e => setNewTaskPoints(Number(e.target.value))}
                                min={0}
                            /> pts
                        </label>
                    </div>
                </form>
            </div>

            {/* Tasks List */}
            <h2 style={{ marginBottom: '24px', display: 'flex', alignItems: 'center', gap: '8px' }}>
                Todas as Tarefas <span style={{ background: 'var(--primary)', color: 'white', padding: '2px 10px', borderRadius: '20px', fontSize: '0.9rem' }}>{tasks.length}</span>
            </h2>

            <div style={{ display: 'flex', flexDirection: 'column', gap: '16px', marginBottom: '48px' }}>
                {loading ? (
                    <div style={{ textAlign: 'center', padding: '40px', color: 'var(--text-secondary)' }}>Carregando tarefas...</div>
                ) : tasks.length === 0 ? (
                    <div className="animate-in" style={{
                        textAlign: 'center',
                        padding: '64px 24px',
                        background: 'var(--glass-bg)',
                        borderRadius: 'var(--radius-lg)',
                        border: '1px dashed var(--border-color)',
                        marginTop: '16px'
                    }}>
                        <CheckSquare size={48} color="var(--primary)" style={{ opacity: 0.5, marginBottom: '16px' }} />
                        <h3 style={{ fontSize: '1.4rem', marginBottom: '8px' }}>Tudo limpo por aqui!</h3>
                        <p style={{ color: 'var(--text-secondary)', maxWidth: '400px', margin: '0 auto' }}>
                            Ainda não há tarefas criadas nesta família. Comece adicionando uma no campo acima para gerar pontos!
                        </p>
                    </div>
                ) : (
                    tasks.map((task, index) => (
                        <div
                            key={task.id}
                            className="glass animate-in"
                            style={{
                                padding: '20px',
                                borderRadius: 'var(--radius-lg)',
                                display: 'flex',
                                alignItems: 'center',
                                gap: '16px',
                                animationDelay: `${index * 0.05}s`,
                                borderLeft: task.isCompleted ? '4px solid var(--success)' : '4px solid transparent',
                                opacity: task.isCompleted ? 0.7 : 1,
                                transition: 'all 0.3s ease'
                            }}
                        >
                            <button
                                onClick={() => handleToggleTask(task.id, task.isCompleted)}
                                style={{
                                    background: 'none',
                                    border: 'none',
                                    cursor: 'pointer',
                                    color: task.isCompleted ? 'var(--success)' : 'var(--text-secondary)',
                                    display: 'flex',
                                    padding: '4px',
                                    alignSelf: 'flex-start',
                                    marginTop: '2px'
                                }}
                            >
                                {task.isCompleted ? <CheckCircle2 size={24} /> : <Circle size={24} />}
                            </button>

                            <div style={{ flex: 1 }}>
                                <div style={{ display: 'flex', alignItems: 'center', gap: '8px', flexWrap: 'wrap' }}>
                                    <p style={{
                                        fontSize: '1.1rem',
                                        color: task.isCompleted ? 'var(--text-secondary)' : 'var(--text-primary)',
                                        textDecoration: task.isCompleted ? 'line-through' : 'none',
                                        fontWeight: 500,
                                        margin: 0
                                    }}>
                                        {task.title}
                                    </p>
                                    {task.category && task.category !== 'geral' && (
                                        <span style={{ fontSize: '0.75rem', padding: '2px 8px', borderRadius: '12px', background: 'rgba(99, 102, 241, 0.2)', color: 'var(--primary)', textTransform: 'uppercase', fontWeight: 600 }}>
                                            {task.category}
                                        </span>
                                    )}
                                    {task.isDaily && <div title="Tarefa Diária" style={{ display: 'flex', color: 'var(--primary)' }}><Calendar size={16} /></div>}
                                    <span style={{ color: 'var(--success)', fontWeight: 'bold', fontSize: '0.9rem', padding: '2px 8px', background: 'rgba(255,255,255,0.05)', borderRadius: 'var(--radius-sm)' }}>
                                        +{task.points} pts
                                    </span>
                                </div>
                                <div style={{ fontSize: '0.8rem', color: 'var(--text-secondary)', display: 'flex', gap: '8px', marginTop: '6px' }}>
                                    <span>Criado por {task.creator.name}</span>
                                    {task.isCompleted && task.completer && (
                                        <>
                                            <span>•</span>
                                            <span>Concluído por {task.completer.name}</span>
                                        </>
                                    )}
                                </div>

                                {task.subtasks && task.subtasks.length > 0 && (
                                    <div style={{ marginTop: '16px', display: 'flex', flexDirection: 'column', gap: '8px', paddingLeft: '8px', borderLeft: '2px solid rgba(255,255,255,0.05)' }}>
                                        {task.subtasks.map(st => (
                                            <div key={st.id} style={{ display: 'flex', alignItems: 'center', gap: '8px', opacity: st.isCompleted ? 0.6 : 1 }}>
                                                <button onClick={() => handleToggleSubtask(task.id, st.id, st.isCompleted)} style={{ background: 'none', border: 'none', cursor: 'pointer', padding: 0, display: 'flex', color: st.isCompleted ? 'var(--success)' : 'var(--text-secondary)' }}>
                                                    {st.isCompleted ? <CheckSquare size={16} /> : <Circle size={16} />}
                                                </button>
                                                <span style={{ fontSize: '0.9rem', textDecoration: st.isCompleted ? 'line-through' : 'none' }}>{st.title}</span>
                                            </div>
                                        ))}
                                    </div>
                                )}

                                {addingSubtaskTo === task.id && (
                                    <div className="animate-in" style={{ marginTop: '12px', display: 'flex', gap: '8px' }}>
                                        <input
                                            autoFocus
                                            type="text"
                                            className="form-input"
                                            placeholder="Nome do item..."
                                            style={{ padding: '4px 8px', fontSize: '0.9rem' }}
                                            value={newSubtaskTitle}
                                            onChange={e => setNewSubtaskTitle(e.target.value)}
                                            onKeyDown={(e) => {
                                                if (e.key === 'Enter') handleAddSubtask(task.id);
                                                if (e.key === 'Escape') setAddingSubtaskTo(null);
                                            }}
                                        />
                                        <button onClick={() => handleAddSubtask(task.id)} className="btn btn-primary" style={{ padding: '4px 12px', fontSize: '0.8rem' }}>Ok</button>
                                        <button onClick={() => setAddingSubtaskTo(null)} className="btn btn-secondary" style={{ padding: '4px' }}>x</button>
                                    </div>
                                )}
                            </div>

                            <div style={{ display: 'flex', flexDirection: 'column', gap: '8px', alignSelf: 'flex-start' }}>
                                <button
                                    onClick={() => {
                                        setAddingSubtaskTo(task.id);
                                        setNewSubtaskTitle('');
                                    }}
                                    className="btn btn-secondary"
                                    style={{ padding: '8px', borderColor: 'transparent', fontSize: '0.8rem' }}
                                    title="Adicionar Sub-tarefa"
                                >
                                    <Plus size={16} /> Item
                                </button>
                                <button
                                    onClick={() => handleDeleteTask(task.id)}
                                    className="btn btn-secondary"
                                    style={{ padding: '8px', color: '#ff4b4b', borderColor: 'transparent' }}
                                    title="Deletar tarefa"
                                >
                                    <Trash2 size={16} />
                                </button>
                            </div>
                        </div>
                    ))
                )}
            </div>

            {/* Add Member Section */}
            <div className="glass glass-card" style={{ borderTop: '1px solid rgba(255,255,255,0.05)' }}>
                <h3 style={{ fontSize: '1.2rem', marginBottom: '16px' }}>Adicionar Membro (Apenas Admin)</h3>
                <form onSubmit={handleAddMember} style={{ display: 'flex', gap: '12px' }}>
                    <input
                        type="email"
                        className="form-input"
                        placeholder="E-mail do novo membro"
                        style={{ flex: 1 }}
                        value={newMemberEmail}
                        onChange={e => setNewMemberEmail(e.target.value)}
                        required
                    />
                    <button type="submit" className="btn btn-secondary">
                        <UserPlus size={18} /> Add
                    </button>
                </form>
            </div>

            {/* Custom Confirmation Modal */}
            {confirmModal.isOpen && (
                <div style={{
                    position: 'fixed', top: 0, left: 0, right: 0, bottom: 0,
                    backgroundColor: 'rgba(0,0,0,0.8)', backdropFilter: 'blur(4px)',
                    display: 'flex', alignItems: 'center', justifyContent: 'center',
                    zIndex: 1000, padding: '20px'
                }}>
                    <div className="glass glass-card animate-in" style={{ maxWidth: '400px', width: '100%', textAlign: 'center' }}>
                        <h3 style={{ marginBottom: '12px' }}>{confirmModal.title}</h3>
                        <p style={{ color: 'var(--text-secondary)', marginBottom: '24px' }}>{confirmModal.message}</p>
                        <div style={{ display: 'flex', gap: '12px', justifyContent: 'center' }}>
                            <button onClick={closeConfirm} className="btn btn-secondary" style={{ flex: 1 }}>Sair</button>
                            <button onClick={confirmModal.onConfirm} className="btn btn-primary" style={{ flex: 1, backgroundColor: confirmModal.title.includes('Excluir') ? '#ff4b4b' : '' }}>Confirmar</button>
                        </div>
                    </div>
                </div>
            )}
        </div>
    );
};

export default GroupDetails;

import React, { useState } from 'react';
import { useNavigate } from 'react-router-dom';
import api from '../services/api';
import { useAuth } from '../context/AuthContext';
import { LogIn, UserPlus } from 'lucide-react';

const AVATARS = [
    { id: 'fox', emoji: '🦊' },
    { id: 'cat', emoji: '🐱' },
    { id: 'dog', emoji: '🐶' },
    { id: 'panda', emoji: '🐼' },
    { id: 'koala', emoji: '🐨' },
    { id: 'lion', emoji: '🦁' },
    { id: 'tiger', emoji: '🐯' },
    { id: 'monkey', emoji: '🐵' },
    { id: 'unicorn', emoji: '🦄' },
    { id: 'alien', emoji: '👽' }
];

const Login: React.FC = () => {
    const [isLogin, setIsLogin] = useState(true);
    const [email, setEmail] = useState('');
    const [password, setPassword] = useState('');
    const [name, setName] = useState('');
    const [avatar, setAvatar] = useState('fox');
    const [error, setError] = useState('');
    const [loading, setLoading] = useState(false);

    const { loadUser } = useAuth();
    const navigate = useNavigate();

    const handleSubmit = async (e: React.FormEvent) => {
        e.preventDefault();
        setError('');
        setLoading(true);

        try {
            const endpoint = isLogin ? '/api/auth/login' : '/api/auth/register';
            const payload = isLogin ? { email, password } : { name, email, password, avatar };

            const { data } = await api.post(endpoint, payload);

            localStorage.setItem('@Famask:token', data.token);
            localStorage.setItem('@Famask:user', JSON.stringify(data.user));
            loadUser();
            navigate('/');
        } catch (err: any) {
            if (err.response?.data?.error) {
                if (Array.isArray(err.response.data.error)) {
                    setError('Dados inválidos. Verifique os campos.');
                } else {
                    setError(err.response.data.error);
                }
            } else {
                setError('Erro na conexão com o servidor.');
            }
        } finally {
            setLoading(false);
        }
    };

    return (
        <div className="login-container" style={{ display: 'flex', alignItems: 'center', justifyContent: 'center', flex: 1 }}>
            <div className="glass glass-card animate-in" style={{ width: '100%', maxWidth: '420px', padding: '40px' }}>
                <div style={{ textAlign: 'center', marginBottom: '2rem' }}>
                    <h1 className="title" style={{ fontSize: '2rem', marginBottom: '0.5rem' }}>Famask</h1>
                    <p className="subtitle" style={{ fontSize: '0.95rem', margin: 0 }}>
                        {isLogin ? 'Bem-vindo de volta à sua família.' : 'Crie sua conta familiar.'}
                    </p>
                </div>

                {error && (
                    <div style={{ background: 'rgba(239, 68, 68, 0.15)', color: 'var(--danger)', padding: '12px', borderRadius: 'var(--radius-sm)', marginBottom: '16px', fontSize: '0.9rem', textAlign: 'center' }}>
                        {error}
                    </div>
                )}

                <form onSubmit={handleSubmit}>
                    {!isLogin && (
                        <>
                            <div className="form-group">
                                <label className="form-label">Nome</label>
                                <input
                                    type="text"
                                    className="form-input"
                                    placeholder="Seu nome"
                                    value={name}
                                    onChange={e => setName(e.target.value)}
                                    required={!isLogin}
                                />
                            </div>
                            <div className="form-group">
                                <label className="form-label">Escolha um Avatar</label>
                                <div style={{ display: 'flex', gap: '8px', flexWrap: 'wrap', justifyContent: 'center', marginBottom: '16px' }}>
                                    {AVATARS.map(av => (
                                        <button
                                            key={av.id}
                                            type="button"
                                            onClick={() => setAvatar(av.id)}
                                            style={{
                                                fontSize: '1.8rem',
                                                padding: '8px',
                                                background: avatar === av.id ? 'var(--primary)' : 'rgba(255,255,255,0.05)',
                                                border: avatar === av.id ? '2px solid white' : '2px solid transparent',
                                                borderRadius: '50%',
                                                cursor: 'pointer',
                                                width: '50px',
                                                height: '50px',
                                                display: 'flex',
                                                alignItems: 'center',
                                                justifyContent: 'center',
                                                transition: 'all 0.2s'
                                            }}
                                        >
                                            {av.emoji}
                                        </button>
                                    ))}
                                </div>
                            </div>
                        </>
                    )}

                    <div className="form-group">
                        <label className="form-label">E-mail</label>
                        <input
                            type="email"
                            className="form-input"
                            placeholder="seu@email.com"
                            value={email}
                            onChange={e => setEmail(e.target.value)}
                            required
                        />
                    </div>

                    <div className="form-group" style={{ marginBottom: '24px' }}>
                        <label className="form-label">Senha</label>
                        <input
                            type="password"
                            className="form-input"
                            placeholder="••••••••"
                            value={password}
                            onChange={e => setPassword(e.target.value)}
                            required
                            minLength={6}
                        />
                    </div>

                    <button
                        type="submit"
                        className="btn btn-primary"
                        style={{ width: '100%', padding: '12px' }}
                        disabled={loading}
                    >
                        {isLogin ? <LogIn size={18} /> : <UserPlus size={18} />}
                        {loading ? 'Aguarde...' : (isLogin ? 'Entrar' : 'Registrar')}
                    </button>
                </form>

                <div style={{ marginTop: '24px', textAlign: 'center' }}>
                    <button
                        type="button"
                        className="btn"
                        style={{ background: 'transparent', color: 'var(--text-secondary)', padding: 0 }}
                        onClick={() => { setIsLogin(!isLogin); setError(''); }}
                    >
                        {isLogin ? 'Não tem uma conta? Registre-se.' : 'Já tem uma conta? Entre.'}
                    </button>
                </div>
            </div>
        </div>
    );
};

export default Login;
